policies.content:
permit(
  principal == User::"alice",
  action == Action::"ViewDocument",
  resource == Document::"doc123"
) when {
  resource.owner == principal
};

package corp.authz

default allow = false

allow {
  input.principal.role == "reader"
  input.action == "read_file"
}

forbid(
  principal,
  action,
  resource
) when {
  principal.status == "suspended"
};
